import{_ as e,c as a,o as f,U as o}from"./chunks/framework.9QHaLlVJ.js";const r="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444532342e706e67.nBJxNvxS.png",t="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444147462e706e67.-1bDiQsr.png",c="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446b50552e706e67.hgDYAjB1.png",d="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d4456784a2e706e67.jr4duUNf.png",p="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446935542e706e67.5wPteoGo.png",s="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446d72522e706e67.CwMedAvb.png",n="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446e71312e706e67.s9igw1K5.png",i="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d44654d392e706e67.muZv-w17.png",A="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444b56782e706e67.UrB4wUhY.png",P="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444d61362e706e67.6_DpIrNb.png",l="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d4451494b2e706e67.vX3GGYz0.png",b="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d4431504f2e706e67.qrViC6MK.png",h="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d447473412e706e67.3A5yLpU4.png",R="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444e71492e706e67.-uYBjWES.png",m="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d443852652e706e67.qMG3M6l3.png",g="/assets/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d44594d642e706e67.zPQyi-nl.png",B=JSON.parse('{"title":"ARP（Address Resolution Protocol）","description":"","frontmatter":{},"headers":[],"relativePath":"doc/网络协议/ARP/ARP.md","filePath":"packages/doc/src/网络协议/ARP/ARP.md","lastUpdated":1704643216000}'),u={name:"doc/网络协议/ARP/ARP.md"},_=o('<h1 id="arp-address-resolution-protocol" tabindex="-1">ARP（Address Resolution Protocol） <a class="header-anchor" href="#arp-address-resolution-protocol" aria-label="Permalink to &quot;ARP（Address Resolution Protocol）&quot;">​</a></h1><h2 id="_1-什么是arp" tabindex="-1">1.什么是ARP？ <a class="header-anchor" href="#_1-什么是arp" aria-label="Permalink to &quot;1.什么是ARP？&quot;">​</a></h2><p>ARP即地址解析协议， 用于实现从 IP 地址到 MAC 地址的映射，即询问目标IP对应的MAC地址。</p><p>只要确定了 IP 地址后，就能够向这个 IP 地址所在的主机发送数据报，这是我们所熟知的事情。但是再往深了想，IP 地址只是标识网络层的地址，那么在网络层下方数据链路层是不是也有一个地址能够告诉对方主机自己的地址呢？是的，这个地址就是<code>MAC 地址</code>。</p><h2 id="认识-mac-地址" tabindex="-1">认识 MAC 地址 <a class="header-anchor" href="#认识-mac-地址" aria-label="Permalink to &quot;认识 MAC 地址&quot;">​</a></h2><p>MAC 地址的全称是 <code>Media Access Control Address</code>，译为媒体访问控制地址，它是网络上以太网或网络适配器的唯一标识符。MAC 地址能够区分不同的网络接口，并用于多种网络技术，尤其是大多数 IEEE 802 网络。</p><blockquote><p>MAC 地址也称为物理地址，硬件地址和老化地址。</p></blockquote><p>MAC 地址主要用于识别数据链路中互联的节点，如下图所示</p><p><a href="https://camo.githubusercontent.com/ffc59abf748c37ba1aaeadb557f59bcc4547eff8fe27596ba3e9a8d7d5edad5d/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444532342e706e67" target="_blank" rel="noreferrer"><img src="'+r+'" alt="img"></a></p><p>MAC 地址长 48 bit，在使用<code>网卡(NIC)</code> 的情况下，MAC 地址一般都会烧入 ROM 中。因此，任何一个网卡的 MAC 地址都是唯一的。MAC 地址的结构如下</p><p><a href="https://camo.githubusercontent.com/44ec797df6cf630e1b957a62bfc05ef505c7fbcfb024309fc30dfee65bb21744/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444147462e706e67" target="_blank" rel="noreferrer"><img src="'+t+'" alt="img"></a></p><p>MAC 地址中的 3 - 24 位表示厂商识别码，每个 NIC 厂商都有特定唯一的识别数字。25 - 48 位是厂商内部为识别每个网卡而用。因此，可以保证全世界不会有相同 MAC 地址的网卡。</p><blockquote><p>MAC 地址也有例外情况，即 MAC 地址也会有重复的时候，但是问题不大，只要两个 MAC 地址是属于不同的数据链路层就不会出现问题。</p></blockquote><h2 id="arp-是什么" tabindex="-1">ARP 是什么 <a class="header-anchor" href="#arp-是什么" aria-label="Permalink to &quot;ARP 是什么&quot;">​</a></h2><p>ARP 协议的全称是 <code>Address Resolution Protocol(地址解析协议)</code>，它是一个通过<strong>用于实现从 IP 地址到 MAC 地址的映射，即询问目标 IP 对应的 MAC 地址</strong> 的一种协议。ARP 协议在 IPv4 中极其重要。</p><blockquote><p>注意：ARP 只用于 IPv4 协议中，IPv6 协议使用的是 Neighbor Discovery Protocol，译为邻居发现协议，它被纳入 ICMPv6 中。</p></blockquote><p>简而言之，ARP 就是一种解决地址问题的协议，它以 IP 地址为线索，定位下一个应该接收数据分包的主机 MAC 地址。如果目标主机不在同一个链路上，那么会查找下一跳路由器的 MAC 地址。</p><h3 id="arp-的工作机制" tabindex="-1">ARP 的工作机制 <a class="header-anchor" href="#arp-的工作机制" aria-label="Permalink to &quot;ARP 的工作机制&quot;">​</a></h3><p>下面我们探讨一下 ARP 的工作机制是怎样的。假设 A 和 B 位于同一链路，不需要经过路由器的转换，主机 A 向主机 B 发送一个 IP 分组，主机 A 的地址是 192.168.1.2 ，主机 B 的地址是 192.168.1.3，它们都不知道对方的 MAC 地址是啥，主机 C 和 主机 D 是同一链路的其他主机。</p><p><a href="https://camo.githubusercontent.com/1b8e078935b2642e13e266286cd17b172d4cd66b6d0dfff328745d8e246f756e/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446b50552e706e67" target="_blank" rel="noreferrer"><img src="'+c+'" alt="img"></a></p><p>主机 A 想要获取主机 B 的 MAC 地址，通过主机 A 会通过<code>广播</code> 的方式向以太网上的所有主机发送一个 <code>ARP 请求包</code>，这个 ARP 请求包中包含了主机 A 想要知道的主机 B 的 IP 地址的 MAC 地址。</p><p><a href="https://camo.githubusercontent.com/93e2da6dac2d75ee3f40a17ddc398d295c962c69ef06f4b139e36cc8b27b571b/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d4456784a2e706e67" target="_blank" rel="noreferrer"><img src="'+d+'" alt="img"></a></p><p>主机 A 发送的 ARP 请求包会被同一链路上的所有主机/路由器接收并进行解析。每个主机/路由器都会检查 ARP 请求包中的信息，如果 ARP 请求包中的<code>目标 IP 地址</code> 和自己的相同，就会将自己主机的 MAC 地址写入响应包返回主机 A</p><p><a href="https://camo.githubusercontent.com/d606a7b63137a2b355e6c300a545726378288149eb60541f2ada5703498846b6/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446935542e706e67" target="_blank" rel="noreferrer"><img src="'+p+'" alt="img"></a></p><p>由此，可以通过 ARP 从 IP 地址获取 MAC 地址，实现同一链路内的通信。</p><blockquote><p>如果是不同链路怎么办呢？</p></blockquote><p>这就要使用到 <code>代理 ARP</code> 了，通常 ARP 会被路由器隔离，但是采用代理 ARP (ARP Proxy) 的路由器可以将 ARP 请求转发给临近的网段。使多个网段中的节点像是在同一网段内通信。</p><h3 id="arp-缓存" tabindex="-1">ARP 缓存 <a class="header-anchor" href="#arp-缓存" aria-label="Permalink to &quot;ARP 缓存&quot;">​</a></h3><p>现在你知道了发送一次 IP 分组前通过发送一次 ARP 请求就能够确定 MAC 地址。那么是不是每发送一次都得经过广播 -&gt; 封装 ARP 响应 -&gt; 返回给主机这一系列流程呢？</p><p>想想看，浏览器是如何做的呢？浏览器内置了缓存能够缓存你最近经常使用的地址，那么 ARP 也是一样的。ARP 高效运行的关键就是维护每个主机和路由器上的 <code>ARP 缓存(或表)</code>。这个缓存维护着每个 IP 到 MAC 地址的映射关系。通过把第一次 ARP 获取到的 MAC 地址作为 IP 对 MAC 的映射关系到一个 ARP 缓存表中，下一次再向这个地址发送数据报时就不再需要重新发送 ARP 请求了，而是直接使用这个缓存表中的 MAC 地址进行数据报的发送。每发送一次 ARP 请求，缓存表中对应的映射关系都会被清除。</p><p>通过 ARP 缓存，降低了网络流量的使用，在一定程度上防止了 ARP 的大量广播。</p><p><a href="https://camo.githubusercontent.com/0852c3835ef2af3abadd2668487442330c937401a9abfbf25e0c69d15977241c/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446d72522e706e67" target="_blank" rel="noreferrer"><img src="'+s+'" alt="img"></a></p><p>一般来说，发送过一次 ARP 请求后，再次发送相同请求的几率比较大，因此使用 ARP 缓存能够减少 ARP 包的发送，除此之外，不仅仅 ARP 请求的发送方能够缓存 ARP 接收方的 MAC 地址，接收方也能够缓存 ARP 请求方的 IP 和 MAC 地址，如下所示</p><p><a href="https://camo.githubusercontent.com/0699f9a1c85edbd271c82bd6047d73d6710627eb51c7f333fe2950b817693391/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d446e71312e706e67" target="_blank" rel="noreferrer"><img src="'+n+'" alt="img"></a></p><p>不过，<strong>MAC 地址的缓存有一定期限，超过这个期限后，缓存的内容会被清除</strong>。</p><p>我们可以在 Linux 或者 Windows 中使用 arp 命令查看 ARP 缓存。选项 -a 用于显示两个系统缓存中所有的缓存项。</p><p>在 Linux 中使用 arp 查询缓存</p><p><a href="https://camo.githubusercontent.com/ab22c887d197f358d81469beeb606913d98cfaa9cb3851675f1529a8c52f2465/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d44654d392e706e67" target="_blank" rel="noreferrer"><img src="'+i+'" alt="img"></a></p><p>主要包含五项</p><ul><li>主机名 --- 对应一个 IP 地址</li><li>硬件地址类型</li><li>硬件地址</li><li>标志</li><li>本地网络接口</li></ul><p>标志主要分为<code>三类</code>: C 、M 或 P，C 表示的是由 ARP 协议动态学习。M 类可以通过 arp -s 增加一条。P 类表示的是 <code>发布</code>，对于任何 P 类项目，主机对输入的 ARP 请求都返回一个 ARP 响应。这个选项用于配置代理 ARP。</p><p>比如我们在 Windows 中进行 ARP 缓存查询</p><p><a href="https://camo.githubusercontent.com/ec2462ffbadc715bf37b3fd1fcc389f0e2fb8ce7ede7c9de5526b44d712e6304/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444b56782e706e67" target="_blank" rel="noreferrer"><img src="'+A+'" alt="img"></a></p><p>Windows 中的 ARP 程序显示了 IPv4 的地址，它的接口是十六进制数，Windows 版本还指出地址是手动输入还是 ARP 动态学习的。在上面的例子中，既有静态的也有动态的。48 位的 MAC 地址被显示为 6 个十六进制数，在 Linux 中使用 <code>:</code> 号，在 Windows 中使用 <code>-</code> 进行分隔。</p><h2 id="arp-结构" tabindex="-1">ARP 结构 <a class="header-anchor" href="#arp-结构" aria-label="Permalink to &quot;ARP 结构&quot;">​</a></h2><p>我们上面说到，ARP 对想要知道 MAC 地址的目标主机会首先发送 ARP 请求，那么这个请求中都携带哪些信息呢？下面 cxuan 就来和你聊一下。下面是在以太网中转换一个 IPv4 的地址常用的 ARP 请求或响应的报文格式。</p><p><a href="https://camo.githubusercontent.com/e97c377c6d43b2ab5907e7bf2bb05e7c289ebd21e5552eedb794c40ea7b5b24e/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444d61362e706e67" target="_blank" rel="noreferrer"><img src="'+P+'" alt="img"></a></p><p>前面 14 个字节构成标准以太网的首部，前两个字段 DST 和 SRC 分别表示 <code>以太网的目的地址</code> 和 <code>以太网的源地址</code>，以太网的目的地址如果是 <code>ff:ff:ff:ff:ff:ff</code> 全部为 1 表示广播地址，在同一广播域中的所有以太网接口可以接收这些帧。后面紧跟着的是 ARP 请求的长度/类型，ARP 请求 和 ARP 应答这个值为 <code>0x0806</code>。</p><ul><li><code>硬件类型</code>表示硬件地址的类型，硬件地址常见的有 MAC 物理或者以太网地址，对于以太网来说，此值为 1。</li><li><code>协议类型</code> 指出映射的协议地址类型，对于 IPv4 地址，这个值是 <code>0x0800</code>。</li><li><code>硬件大小</code>和 <code>协议大小</code> 分别指出硬件地址和协议地址的字节数。对于以太网中使用 IPv4 的 ARP 请求或应答，它们的值分别是 6 和 4。</li><li><code>Op</code> 字段指出如果是 ARP 请求，Op = 1，ARP 应答 ，Op = 2，RARP 请求 Op = 3，RARP 应答，Op = 4。</li><li>紧跟在 Op 之后的是 <code>发送方硬件地址(MAC 地址)</code>，<code>发送方的协议地址(IPv4 地址)</code>，<code>目的硬件地址</code> 和 <code>目的协议地址</code>。</li></ul><h2 id="arp-抓包实战" tabindex="-1">ARP 抓包实战 <a class="header-anchor" href="#arp-抓包实战" aria-label="Permalink to &quot;ARP 抓包实战&quot;">​</a></h2><p>我们分别演示在 Mac 和 Linux 下的 ARP 报文的截获</p><p>在 Mac 环境下，我这边使用的是 <code>WireShark</code> 进行抓包，你可以从官网下载，地址如下</p><p><a href="https://links.jianshu.com/go?to=https%3A%2F%2Fwww.wireshark.org%2Fdownload.html" target="_blank" rel="noreferrer">https://www.wireshark.org/download.html</a></p><p><a href="https://camo.githubusercontent.com/3dde776b2999a8896c0e7e8d0a7dfcf983c0ba64c724854b00da4e9315557440/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d4451494b2e706e67" target="_blank" rel="noreferrer"><img src="'+l+'" alt="img"></a></p><p>下载完成后阅读安装说明的手册，阅读后会发现需要安装两个插件，根据提示安装即可，然后我们打开 WireShark ，开始报文拦截，下面是我解惑的 ARP 数据包</p><p><a href="https://camo.githubusercontent.com/5d211703d5729084ba6b6bbe31ad2c73b15026efa6692f983b4f6c91cfa6e572/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d4431504f2e706e67" target="_blank" rel="noreferrer"><img src="'+b+'" alt="img"></a></p><p>这款软件很好的一个地方是对不同的数据包会有不同的颜色标识，这点非常好。</p><p>然后我们查看 ARP 请求</p><p><a href="https://camo.githubusercontent.com/4f0fe7ce01cf737486059fe578b14b6b9a2b4e2410761742a9526aed25bbb221/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444778482e706e67" target="_blank" rel="noreferrer"><img src="https://camo.githubusercontent.com/4f0fe7ce01cf737486059fe578b14b6b9a2b4e2410761742a9526aed25bbb221/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444778482e706e67" alt="img"></a></p><p>可以看到，这就是一个完整的 ARP 请求包，我们使用的硬件类型是以太网，协议类型是 IPv4 ，默认值是 0x0800，然后硬件大小是 6 个字节，协议大小占用 2 个字节，Op 的全称是 Opcode ，Op = 1 表示这是一个 ARP 请求，然后是发送方的硬件地址和协议地址，接收方的硬件地址和协议地址。</p><p>ARP 响应如下</p><p><a href="https://camo.githubusercontent.com/1b71cd866777933169116c00f7411b4c86c1325158c910ab72b64baf41d5c425/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d447473412e706e67" target="_blank" rel="noreferrer"><img src="'+h+'" alt="img"></a></p><p>可以看到 Op = 2，表示这是 ARP 响应。</p><p>在 Linux 环境下，你可以使用 <code>tcpdump</code> 截获 ARP 数据包，如果 tcpdump not found 的话，你可以使用 <code>yum install -y tcpdump</code> 安装。</p><p>使用 <code>tcpdump -i ens33</code> 可以打印出在 ens33 地址下的数据包，下面是我截取的 ARP 数据包。</p><p><a href="https://camo.githubusercontent.com/89f58db4c5c6b39951d72d8f893206bcbeb55e30ed0ed3b04b033ae6d587f121/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d444e71492e706e67" target="_blank" rel="noreferrer"><img src="'+R+'" alt="img"></a></p><p>更多关于 tcpdump 的用法，你可以参考这篇博客</p><p><a href="https://www.cnblogs.com/ggjucheng/archive/2012/01/14/2322659.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/ggjucheng/archive/2012/01/14/2322659.html</a></p><p>大佬写的很详细，这里就不再说明了。</p><h2 id="arp-缓存超时" tabindex="-1">ARP 缓存超时 <a class="header-anchor" href="#arp-缓存超时" aria-label="Permalink to &quot;ARP 缓存超时&quot;">​</a></h2><p>缓存超时通常与 ARP 缓存中的项有关系，arp 命令可以允许管理员设置永不超时。ARP 把保存在高速缓存中的每一映射地址都设置生存时间，一般为 20 分钟。如果是不完整的映射，那么缓存超时时间为 3 分钟，不完整的映射通常会强制发送一条不存在主机的 ARP 请求。</p><h2 id="rarp" tabindex="-1">RARP <a class="header-anchor" href="#rarp" aria-label="Permalink to &quot;RARP&quot;">​</a></h2><p>与 ARP 相对的，<code>RARP(Reverse Address Resolution Protocol)</code> 是将 ARP 反过来，从 MAC 地址定位 IP 地址的一种协议，将打印机服务器等小型嵌入式设备接入网络时会使用到。</p><p><a href="https://camo.githubusercontent.com/31027960d3aaa10a2d3c4b1c5f026517d3f0ade0e6c1d93b7471f998c19c1821/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d443852652e706e67" target="_blank" rel="noreferrer"><img src="'+m+'" alt="img"></a></p><p>平常我们设置 IP 地址一般会有两种方式，<code>手动设置</code> 和 <code>DHCP 动态获取</code></p><p><a href="https://camo.githubusercontent.com/28345a979429b5444b87d90bdc9fe3bdc75fdac981a514602ce0ee7b08540903/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d44615a742e706e67" target="_blank" rel="noreferrer"><img src="https://camo.githubusercontent.com/28345a979429b5444b87d90bdc9fe3bdc75fdac981a514602ce0ee7b08540903/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d44615a742e706e67" alt="img"></a></p><p>但是对于嵌入式设备来说，它没有任何输入接口，也无法通过 DHCP 获取动态地址。</p><p>在这种情况下，就要使用到 RARP 了，你需要准备一个 RARP 服务器，在这个服务器上注册设备的 MAC 地址和 IP 地址，然后将设备接入网络，设备会发出一条 IP 和 MAC 地址的查询请求给服务器，服务器会告诉设备其 IP 地址和 MAC 地址。</p><p><a href="https://camo.githubusercontent.com/2b1dd9d3aa9bf0945d8637026daead801f67faf0674ccc414fc45755f4b3b270/68747470733a2f2f73332e617831782e636f6d2f323032312f30312f30392f734d44594d642e706e67" target="_blank" rel="noreferrer"><img src="'+g+'" alt="img"></a></p><h2 id="arp-攻击" tabindex="-1">ARP 攻击 <a class="header-anchor" href="#arp-攻击" aria-label="Permalink to &quot;ARP 攻击&quot;">​</a></h2><p><strong>ARP 是一种非常不安全的协议</strong>，目前已经有很多涉及 ARP 的攻击，最主要的就是使用代理 ARP 功能假扮主机，对 ARP 请求作出应答，通过伪造 ARP 数据包来窃取合法用户的通信数据，造成影响网络传输速率和盗取用户隐私信息等严重危害。</p><h3 id="arp-攻击分类" tabindex="-1">ARP 攻击分类 <a class="header-anchor" href="#arp-攻击分类" aria-label="Permalink to &quot;ARP 攻击分类&quot;">​</a></h3><p>ARP 主要攻击方式分为下面这几种</p><ul><li><code>ARP 泛洪攻击</code>：通过向网关发送大量 ARP 报文，导致网关无法正常响应。首先发送大量的 ARP 请求报文，然后又发送大量虚假的 ARP 响应报文，从而造成网关部分的 CPU 利用率上升难以响应正常服务请求，而且网关还会被错误的 ARP 缓存表充满导致无法更新维护正常 ARP 缓存表，消耗网络带宽资源。</li><li><code>ARP 欺骗主机攻击</code>：ARP 欺骗主机的攻击也是 ARP 众多攻击类型中很常见的一种。攻击者通过 ARP 欺骗使得局域网内被攻击主机发送给网关的流量信息实际上都发送给攻击者。主机刷新自己的 ARP 使得在自己的ARP 缓存表中对应的 MAC 为攻击者的 MAC，这样一来其他用户要通过网关发送出去的数据流就会发往主机这里，这样就会造成用户的数据外泄。</li><li><code>欺骗网关的攻击</code>: 欺骗网关就是把别的主机发送给网关的数据通过欺骗网关的形式使得这些数据通过网关发送给攻击者。这种攻击目标选择的不是个人主机而是局域网的网关，这样就会攻击者源源不断的获取局域网内其他用户韵数据．造成数据的泄露，同时用户电脑中病毒的概率也会提升。</li><li><code>中间人攻击</code>: 中间人攻击是同时欺骗局域网内的主机和网关，局域网中用户的数据和网关的数据会发给同一个攻击者，这样，用户与网关的数据就会泄露。</li><li><code>IP地址冲突攻击</code>: 通过对局域网中的物理主机进行扫描，扫描出局域网中的物理主机的 MAC 地址，然后根据物理主机的 MAC 进行攻击，导致局域网内的主机产生 IP 地址冲突，影响用户的网络正常使用。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>ARP 是 TCP/IP 实现中的一个基本协议，它通常在应用程序或用户没有察觉到的情况下运行。ARP 可以用于映射 IP 地址为 MAC 地址。</p><p><strong>这篇文章我们主要讲了 ARP 的基本原理，ARP 的帧结构，ARP 的工作机制，以及 ARP 代理、ARP 攻击、RARP 和 ARP 的区别</strong>等。</p>',87),C=[_];function M(k,I,q,x,w,v){return f(),a("div",null,C)}const S=e(u,[["render",M]]);export{B as __pageData,S as default};
